<?php
namespace Tests\Feature;
use App\Domain\WorldMaps\Exceptions\WorldMapNotResolvableException;use App\Domain\WorldMaps\WorldMapReadService;use App\Domain\WorldMaps\WorldMapResolver;use App\Models\Character;use App\Models\Region;use App\Models\User;use App\Models\World;use App\Models\WorldMap;use App\Models\WorldMapArea;use App\Models\Zone;use Carbon\CarbonImmutable;use Database\Seeders\WorldCatalogSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\DB;use Illuminate\Support\Facades\Storage;use Tests\TestCase;
class WorldMapPlayerTest extends TestCase{
use RefreshDatabase;private $character;private $world;private $region;private $zone;
protected function setUp():void{parent::setUp();$this->seed(WorldCatalogSeeder::class);Storage::fake('public');Storage::disk('public')->put('maps/player.png','image');$this->world=World::where('code','eldoria')->firstOrFail();$this->region=Region::where('code','kingdom_of_valtheria')->firstOrFail();$this->zone=Zone::where('code','grey_oak_forest')->firstOrFail();$this->character=Character::factory()->for(User::factory())->create();}
private function map($code,$context=[],$default=false,$status='active'){return WorldMap::create(array_merge(['world_id'=>$this->world->id,'region_id'=>null,'code'=>$code,'name'=>$code,'image_disk'=>'public','image_path'=>'maps/player.png','original_width'=>640,'original_height'=>360,'mime_type'=>'image/png','file_size'=>5,'version'=>1,'status'=>$status,'is_default'=>$default,'sort_order'=>0],$context));}
private function area($map,$code,$type='info',$extra=[]){return WorldMapArea::create(array_merge(['world_map_id'=>$map->id,'code'=>$code,'name'=>$code,'description'=>'Plain panel text','polygon_points'=>['coordinate_system'=>'normalized','points'=>[['x'=>0.1,'y'=>0.1],['x'=>0.4,'y'=>0.1],['x'=>0.2,'y'=>0.4]]],'action_type'=>$type,'display_mode'=>'panel','z_index'=>0,'status'=>'active','sort_order'=>0,'version'=>1],$extra));}
public function test_active_map_and_area_render_accessible_svg_without_executing_hunt(){$map=$this->map('player_map',[],true);$area=$this->area($map,'zone_area','zone',['zone_id'=>$this->zone->id,'description'=>null]);$geometry=$area->fresh()->polygon_points;$before=DB::table('hunts')->count();$response=$this->actingAs($this->character->user)->get(route('world-maps.show',$map));$response->assertOk()->assertSee('world-map-player-canvas')->assertSee('data-world-map-player',false)->assertSee('data-world-map-player-image',false)->assertSee('data-world-map-player-svg',false)->assertSee('data-world-map-status',false)->assertSee('data-world-map-panel',false)->assertSee('viewBox="0 0 640 360"',false)->assertSee('preserveAspectRatio="xMidYMid meet"',false)->assertSee('points="64,36 256,36 128,144"',false)->assertSee('tabindex="0"',false)->assertSee('data-world-map-area',false)->assertSee('hunt_url');$this->assertSame($geometry,$area->fresh()->polygon_points);$this->assertSame($before,DB::table('hunts')->count());}
public function test_inactive_content_is_hidden_and_out_of_window_is_disabled(){$map=$this->map('visibility_map',[],true);$this->area($map,'active_info');$this->area($map,'hidden_info','info',['status'=>'inactive']);$this->area($map,'future_info','info',['available_from'=>CarbonImmutable::now()->addDay()]);$response=$this->actingAs($this->character->user)->get(route('world-maps.show',$map));$response->assertSee('active_info')->assertDontSee('hidden_info')->assertSee('aria-disabled="true"',false)->assertSee('Disponible a partir de');$inactive=$this->map('inactive_map',[],false,'inactive');$this->actingAs($this->character->user)->get(route('world-maps.show',$inactive))->assertNotFound();}
public function test_default_resolver_and_internal_route_protect_character(){$map=$this->map('default_map',[],true);$this->assertSame($map->id,app(WorldMapResolver::class)->forWorld($this->world)->id);$this->area($map,'profile','internal_route',['internal_route_name'=>'profile','internal_route_parameters'=>null]);$data=app(WorldMapReadService::class)->show($map,$this->character);$this->assertSame(route('characters.show',$this->character),$data['areas'][0]['action']['navigation_url']);WorldMap::whereKey($map->id)->update(['is_default'=>false]);$this->expectException(WorldMapNotResolvableException::class);app(WorldMapResolver::class)->forWorld($this->world);}
public function test_batch_loading_has_stable_query_bound_for_mixed_areas(){$map=$this->map('batch_map',[],true);$target=$this->map('target_map');$this->map('region_map',['world_id'=>null,'region_id'=>$this->region->id],true);foreach(range(1,4) as $i)$this->area($map,'zone_'.$i,'zone',['zone_id'=>$this->zone->id,'description'=>null]);foreach(range(1,2) as $i)$this->area($map,'map_'.$i,'map',['target_world_map_id'=>$target->id,'description'=>null]);$this->area($map,'world','world',['target_world_id'=>$this->world->id,'description'=>null]);$this->area($map,'region','region',['target_region_id'=>$this->region->id,'description'=>null]);$this->area($map,'info');DB::flushQueryLog();DB::enableQueryLog();$result=app(WorldMapReadService::class)->show($map,$this->character);$this->assertCount(9,$result['areas']);$this->assertLessThanOrEqual(18,count(DB::getQueryLog()));}
public function test_player_assets_define_idempotent_accessible_interaction_and_loading_states(){$javascript=file_get_contents(base_path('src/assets/js/world-map-player.js'));$styles=file_get_contents(base_path('src/assets/scss/_world-map.scss'));$this->assertStringContainsString("dataset.worldMapPlayerInitialized === 'true'",$javascript);$this->assertStringContainsString("querySelectorAll('[data-world-map-player]')",$javascript);$this->assertStringContainsString("querySelectorAll('[data-world-map-area]')",$javascript);$this->assertStringContainsString('image.complete',$javascript);$this->assertStringContainsString('image.naturalWidth > 0',$javascript);$this->assertStringContainsString("event.key === 'Enter' || event.key === ' '",$javascript);$this->assertStringContainsString('window.location.assign(data.navigation_url)',$javascript);foreach(['map','world','region','internal_route'] as $type)$this->assertStringContainsString("'".$type."'",$javascript);$this->assertStringContainsString('.world-map-player-canvas.is-ready .world-map-overlay',$styles);$this->assertStringContainsString('pointer-events: auto',$styles);$this->assertStringContainsString('.world-map-player-area',$styles);$this->assertStringContainsString('pointer-events: all',$styles);$this->assertStringContainsString('.world-map-image',$styles);$this->assertStringContainsString('pointer-events: none',$styles);$this->assertStringContainsString('var(--world-map-hover-fill)',$styles);}
public function test_player_visual_states_are_scoped_and_menu_is_active_for_every_player_map_route(){$styles=preg_replace('/\s+/','',file_get_contents(base_path('src/assets/scss/_world-map.scss')));$javascript=file_get_contents(base_path('src/assets/js/world-map-player.js'));$navigation=file_get_contents(resource_path('views/layouts/partials/global-navigation.blade.php'));$this->assertStringContainsString("request()->routeIs('world-maps.*')",$navigation);$this->assertStringContainsString("route('world-maps.index')",$navigation);$this->assertStringContainsString('.world-map-player-area{cursor:pointer;pointer-events:all;fill-opacity:.06!important;stroke-opacity:.25!important;stroke-width:1.25!important}',$styles);$this->assertStringContainsString('fill-opacity:clamp(.28,var(--world-map-hover-opacity),.40)!important',$styles);$this->assertStringContainsString('.world-map-player-area.is-selected{',$styles);$this->assertStringContainsString('fill-opacity:.22!important',$styles);$this->assertStringContainsString('.world-map-player-area.is-disabled{cursor:not-allowed;fill-opacity:.03!important;stroke-opacity:.20!important}',$styles);$this->assertStringContainsString("classList.add('is-selected')",$javascript);$this->assertStringContainsString("setAttribute('aria-pressed', 'true')",$javascript);$worldMap=$this->map('menu_world',[],true);$regionMap=$this->map('menu_region',['world_id'=>null,'region_id'=>$this->region->id],true);$this->area($worldMap,'menu_info');$this->area($regionMap,'region_info');$this->actingAs($this->character->user);foreach([route('world-maps.index'),route('world-maps.show',$worldMap),route('world-maps.world',$this->world),route('world-maps.region',$this->region)] as $url){$this->followingRedirects()->get($url)->assertOk()->assertSee('nav-link active" href="'.route('world-maps.index'),false)->assertSee('ti ti-map-2',false)->assertDontSee(route('admin.content.world-maps.index'),false);}}
}
